const raw = ($input.first().json.text || '').trim();
let parsed;

try {
  parsed = JSON.parse(raw);
} catch {
  const fenced = raw.match(/```(?:json)?\n([\s\S]*?)\n```/i);
  if (!fenced) {
    throw new Error('Generate Recipe Idea did not return valid JSON: ' + raw);
  }
  parsed = JSON.parse(fenced[1]);
}

const selected = parsed.selected || parsed;

const recipeName = (selected.recipe_name || '').trim();
if (!recipeName) {
  throw new Error('Missing recipe_name in Generate Recipe Idea output.');
}

const slug = (selected.slug || recipeName)
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '');

return [{
  json: {
    recipe_name: recipeName,
    slug,
    why_fit: (selected.why_fit || '').trim(),
    cuisine: (selected.cuisine || '').trim(),
    meal_type: (selected.meal_type || '').trim(),
    protein: (selected.protein || '').trim(),
    gap_analysis: (parsed.gap_analysis || '').trim(),
    candidates: parsed.candidates || []
  }
}];

const newTreeSha = $input.first().json.sha;
const parentSha = $('Build Main Tree Request1').first().json.parent_commit_sha;
const message = $('Build Main Tree Request1').first().json.commit_message;
return [{
  json: {
    body: {
      message: message,
      tree: newTreeSha,
      parents: [parentSha]
    }
  }
}];

const cleanData = $('Remove Draft Frontmatter1').first().json;
const branchInfo = $input.first().json;
const parentCommitSha = branchInfo.commit.sha;
const currentTreeSha = branchInfo.commit.commit.tree.sha;
const defaultBranch = $('Get Repo Info1').first().json.default_branch;
return [{
  json: {
    body: {
      base_tree: currentTreeSha,
      tree: [
        { path: 'recipes/en/' + cleanData.en_filename, mode: '100644', type: 'blob', content: cleanData.en_content },
        { path: 'recipes/es/' + cleanData.es_filename, mode: '100644', type: 'blob', content: cleanData.es_content }
      ]
    },
    parent_commit_sha: parentCommitSha,
    commit_message: cleanData.commit_message,
    default_branch: defaultBranch
  }
}];

const draftData = $('Inject Draft Frontmatter1').first().json;
function removeDraft(content) {
  return content.replace(/^---\ndraft: true\n/, '---\n');
}
return [{
  json: {
    en_filename: draftData.en_filename,
    en_content: removeDraft(draftData.en_content),
    es_filename: draftData.es_filename,
    es_content: removeDraft(draftData.es_content),
    commit_message: draftData.commit_message
  }
}];

const data = $('Build Preview URL1').first().json;

let parsedRecipe = {};
try { parsedRecipe = $('Parse Recipe Idea').first().json || {}; } catch (e) {}

const gapAnalysis = parsedRecipe.gap_analysis
  ? '\n\n<b>Gap filled:</b> ' + parsedRecipe.gap_analysis
  : '';
const whyFit = parsedRecipe.why_fit
  ? '\n<b>Why this recipe:</b> ' + parsedRecipe.why_fit
  : '';

const candidates = parsedRecipe.candidates || [];
const candidatesText = candidates.length > 0
  ? '\n\n<b>Other candidates considered:</b>\n' +
    candidates.map((c, i) => (i + 1) + '. ' + c.recipe_name + ' (' + c.cuisine + ', ' + c.meal_type + ')').join('\n')
  : '';

const text = '<b>New Recipe Draft: ' + data.recipeName + '</b>\n\nA new recipe has been generated and is ready for your review.' +
  gapAnalysis + whyFit + candidatesText +
  '\n\n<b>Preview:</b>\n' + data.previewUrl;
return [{ json: { text } }];

const draftData = $('Inject Draft Frontmatter1').first().json;
const resumeUrl = $execution.resumeUrl;
const slug = draftData.recipe_slug;
const previewUrl = 'https://lowkeycooking-blog-git-drafts-christophcharafs-projects.vercel.app/en/recipes/' + slug;
const approveUrl = resumeUrl + '&action=approve';
const rejectUrl = resumeUrl + '&action=reject';
const recipeName = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
return [{ json: { previewUrl, approveUrl, rejectUrl, slug, recipeName } }];

const newTreeSha = $input.first().json.sha;
const parentSha = $('Build Create Tree Request1').first().json.parent_commit_sha;
const message = $('Build Create Tree Request1').first().json.commit_message;

return [{
  json: {
    body: {
      message: message,
      tree: newTreeSha,
      parents: [parentSha]
    }
  }
}];

const draftData = $('Inject Draft Frontmatter1').first().json;
const branchInfo = $input.first().json;
// GET /branches/{branch} returns: { commit: { sha, commit: { tree: { sha } } } }
const parentCommitSha = branchInfo.commit.sha;
const currentTreeSha = branchInfo.commit.commit.tree.sha;

return [{
  json: {
    body: {
      base_tree: currentTreeSha,
      tree: [
        {
          path: 'recipes/en/' + draftData.en_filename,
          mode: '100644',
          type: 'blob',
          content: draftData.en_content
        },
        {
          path: 'recipes/es/' + draftData.es_filename,
          mode: '100644',
          type: 'blob',
          content: draftData.es_content
        }
      ]
    },
    parent_commit_sha: parentCommitSha,
    commit_message: draftData.commit_message,
    default_branch: 'drafts'
  }
}];

const prepareData = $input.first().json;

function addDraft(content) {
  return content.replace(/^---\n/, '---\ndraft: true\n');
}

const slug = prepareData.en_filename.replace('.md', '');

return [{
  json: {
    en_filename: prepareData.en_filename,
    en_content: addDraft(prepareData.en_content),
    es_filename: prepareData.es_filename,
    es_content: addDraft(prepareData.es_content),
    commit_message: prepareData.commit_message,
    recipe_slug: slug
  }
}];

const items = $input.all();
const en = items.find(i => i.json.lang === 'en');
const es = items.find(i => i.json.lang === 'es');

if (!en || !es) {
  throw new Error('Missing language variant. Got: ' + JSON.stringify(items.map(i => i.json.lang)));
}

const recipeName = en.json.filename.replace('.md', '');

return [{
  json: {
    en_filename: en.json.filename,
    en_content: en.json.content,
    es_filename: es.json.filename,
    es_content: es.json.content,
    commit_message: 'feat: add ' + recipeName + ' recipe (EN + ES)'
  }
}];

const item = $input.first().json;
const raw = item.text ?? item.output ?? item.response ?? item.content ?? '';
if (!raw) throw new Error('No content from AI node. Keys received: ' + Object.keys(item).join(', '));

let content = raw
  .replace(/^```(?:markdown|md)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const filenameMatch = content.match(/<!--\s*filename:\s*([\w-]+\.md)\s*-->/);
const filename = filenameMatch ? filenameMatch[1] : 'recipe-' + Date.now() + '.md';

const cleanContent = content
  .replace(/<!--\s*filename:[^>]+-->\n?/, '')
  .trim();

return [{ json: { filename, content: cleanContent, lang: 'es' } }];

const item = $input.first().json;
const raw = item.text ?? item.output ?? item.response ?? item.content ?? '';
if (!raw) throw new Error('No content from AI node. Keys received: ' + Object.keys(item).join(', '));

let content = raw
  .replace(/^```(?:markdown|md)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const filenameMatch = content.match(/<!--\s*filename:\s*([\w-]+\.md)\s*-->/);
const filename = filenameMatch ? filenameMatch[1] : 'recipe-' + Date.now() + '.md';

const cleanContent = content
  .replace(/<!--\s*filename:[^>]+-->\n?/, '')
  .trim();

return [{ json: { filename, content: cleanContent, lang: 'en' } }];

const results = $input.first().json.results || [];
const recipeName = $('Parse Recipe Idea').first().json.recipe_name || $('Fallback Recipe Idea').first().json.recipe_name;

if (!results.length) throw new Error('No photos found for: ' + recipeName);

const imageUrl = results[0].urls.regular.split('?')[0] + '?w=1200&q=80';

return [{ json: { recipe_name: recipeName, image_url: imageUrl } }];

const fileData = $input.first().json;
let recipes = [];
let fileSha = '';

try {
  const decoded = Buffer.from(fileData.content, 'base64').toString('utf8');
  const content = JSON.parse(decoded);
  recipes = content.recipes || [];
  fileSha = fileData.sha || '';
} catch (e) {
  recipes = [];
  fileSha = '';
}

const published = recipes.filter(r => r.status === 'published');
const allSlugs = recipes.map(r => r.slug);

const byCuisine = {};
const byMealType = {};
const byProtein = {};

for (const r of published) {
  byCuisine[r.cuisine] = (byCuisine[r.cuisine] || 0) + 1;
  byMealType[r.meal_type] = (byMealType[r.meal_type] || 0) + 1;
  if (r.protein && r.protein !== 'no specific protein — vegetable-forward') {
    byProtein[r.protein] = (byProtein[r.protein] || 0) + 1;
  }
}

const historySummary = [
  'By cuisine: ' + JSON.stringify(byCuisine),
  'By meal type: ' + JSON.stringify(byMealType),
  'By protein: ' + JSON.stringify(byProtein),
  'Total published: ' + published.length
].join('\n');

const now = new Date();
const month = now.getMonth() + 1;
let season;
if (month === 12 || month === 1 || month === 2) season = 'winter';
else if (month >= 3 && month <= 5) season = 'spring';
else if (month >= 6 && month <= 8) season = 'summer';
else season = 'fall';

return [{ json: {
  exclude_slugs: allSlugs.join(', '),
  history_summary: historySummary,
  file_sha: fileSha,
  season
} }];

const fileData = $input.first().json;
let currentContent;
let fileSha;

try {
  currentContent = JSON.parse(Buffer.from(fileData.content, 'base64').toString('utf8'));
  fileSha = fileData.sha;
} catch (e) {
  currentContent = { recipes: [] };
  fileSha = fileData.sha || '';
}

let parsedRecipe = {};
try {
  const pr = $('Parse Recipe Idea').first().json;
  if (pr && pr.slug) parsedRecipe = pr;
} catch (e) {}

if (!parsedRecipe.slug) {
  try { parsedRecipe = $('Fallback Recipe Idea').first().json || {}; } catch (e) {}
}

const newRecipe = {
  slug: parsedRecipe.slug || '',
  name: parsedRecipe.recipe_name || '',
  status: 'published',
  cuisine: parsedRecipe.cuisine || '',
  meal_type: parsedRecipe.meal_type || '',
  protein: parsedRecipe.protein || '',
  published_at: new Date().toISOString().split('T')[0]
};

const alreadyExists = !newRecipe.slug || currentContent.recipes.some(r => r.slug === newRecipe.slug);
if (!alreadyExists) {
  currentContent.recipes.push(newRecipe);
}

const newContentBase64 = Buffer.from(JSON.stringify(currentContent, null, 2)).toString('base64');

return [{ json: { body: {
  message: 'chore: update recipe history — add ' + (newRecipe.slug || 'unknown'),
  content: newContentBase64,
  sha: fileSha
} } }];
